package com.weekend.architect.unift.auth.controller;import com.weekend.architect.unift.auth.dto.AuthResponse;import com.weekend.architect.unift.auth.dto.LoginRequest;import com.weekend.architect.unift.auth.dto.RefreshTokenRequest;import com.weekend.architect.unift.auth.dto.RegisterRequest;import com.weekend.architect.unift.auth.service.AuthService;import jakarta.servlet.http.HttpServletRequest;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.PostMapping;import org.springframework.web.bind.annotation.RequestBody;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RestController;import java.util.Map;@RestController@RequestMapping("/api/auth")@RequiredArgsConstructorpublic class AuthController {    private final AuthService authService;    /**     * POST /api/auth/register     * Create a new account and return a token pair.     */    @PostMapping("/register")    public ResponseEntity<AuthResponse> register(@Valid @RequestBody RegisterRequest request) {        return ResponseEntity.status(HttpStatus.CREATED).body(authService.register(request));    }    /**     * POST /api/auth/login     * Authenticate with username (or email) + password and return a token pair.     */    @PostMapping("/login")    public ResponseEntity<AuthResponse> login(            @Valid @RequestBody LoginRequest request,            HttpServletRequest httpRequest    ) {        String deviceHint = httpRequest.getHeader("User-Agent");        return ResponseEntity.ok(authService.login(request, deviceHint));    }    /**     * POST /api/auth/refresh     * Exchange a valid refresh token for a new access token (token rotation).     */    @PostMapping("/refresh")    public ResponseEntity<AuthResponse> refresh(@Valid @RequestBody RefreshTokenRequest request) {        return ResponseEntity.ok(authService.refresh(request));    }    /**     * POST /api/auth/logout     * Revoke the provided refresh token.     */    @PostMapping("/logout")    public ResponseEntity<Map<String, String>> logout(@Valid @RequestBody RefreshTokenRequest request) {        authService.logout(request);        return ResponseEntity.ok(Map.of("message", "Logged out successfully"));    }}